#!/usr/bin/env python3
from __future__ import annotations
from pathlib import Path
import sys

def find_repo_root() -> Path:
    here = Path(__file__).resolve()
    for candidate in [here.parent, *here.parents]:
        if (candidate / 'src').exists() and ((candidate / '.git').exists() or (candidate / 'config').exists()):
            return candidate
    return Path.cwd().resolve()

ROOT = find_repo_root()
MONITOR_STATUS = 'from __future__ import annotations\n\n"""Compact status payload for the M8 Sleep Replay Monitor window."""\n\nfrom typing import Any, Dict\n\nimport torch\n\n\ndef _scalar(x: Any, default: float = 0.0) -> float:\n    try:\n        if torch.is_tensor(x):\n            if x.numel() == 0:\n                return float(default)\n            return float(x.detach().float().reshape(-1)[0].cpu().item())\n        if x is None:\n            return float(default)\n        return float(x)\n    except Exception:\n        return float(default)\n\n\ndef _norm(x: Any, default: float = 0.0) -> float:\n    try:\n        if torch.is_tensor(x):\n            if x.numel() == 0:\n                return float(default)\n            return float(x.detach().float().norm().cpu().item())\n        return float(default)\n    except Exception:\n        return float(default)\n\n\ndef _text(x: Any, default: str = "") -> str:\n    try:\n        if x is None:\n            return default\n        return str(x)\n    except Exception:\n        return default\n\n\ndef _dict(x: Any) -> Dict[str, Any]:\n    return x if isinstance(x, dict) else {}\n\n\ndef build_sleep_replay_monitor_status(system: Any) -> Dict[str, Any]:\n    """Build a JSON-safe live monitor payload from the current runtime state."""\n    out = _dict(getattr(system, "latest_out", {}) or {})\n    trace = _dict(out.get("unconscious_loop_trace"))\n    affect = _dict(out.get("affect"))\n    emotion = _dict(out.get("emotion"))\n    m13 = _dict(out.get("autobiographical_memory"))\n    m4 = _dict(out.get("long_dynamic_memory"))\n    m2 = _dict(out.get("event_dream_replay"))\n    focus_feedback = _dict(out.get("focus_feedback"))\n    attention = _dict(out.get("attention"))\n    sleep_motor = _dict(out.get("sleep_motor_guard"))\n\n    full_sleep = bool(system.is_full_sleep_mode()) if hasattr(system, "is_full_sleep_mode") else False\n    sensor_state = system.sensor_state_label() if hasattr(system, "sensor_state_label") else "unknown"\n    sensors = system.input_sensors_enabled_dict() if hasattr(system, "input_sensors_enabled_dict") else {\n        "video": bool(getattr(system, "video_sensor_enabled", True)),\n        "contact": bool(getattr(system, "contact_sensor_enabled", True)),\n        "imu": bool(getattr(system, "imu_sensor_enabled", True)),\n    }\n\n    trace_m11 = _dict(trace.get("m11"))\n    trace_m13 = _dict(trace.get("m13"))\n    trace_m4 = _dict(trace.get("m4"))\n    trace_m2 = _dict(trace.get("m2"))\n    trace_m5 = _dict(trace.get("m5_seed"))\n    trace_m3 = _dict(trace.get("m3"))\n\n    seed = m2.get("next_focus_context_seed", m2.get("replay_context"))\n    seed_gate = m2.get("next_focus_context_seed_gate", m2.get("replay_gate"))\n\n    return {\n        "global_step": int(getattr(system, "global_step", 0)),\n        "full_sleep": bool(full_sleep),\n        "sensor_state": str(sensor_state),\n        "sensors": {\n            "video": bool(sensors.get("video", True)),\n            "contact": bool(sensors.get("contact", True)),\n            "imu": bool(sensors.get("imu", True)),\n        },\n        "m1": {\n            "state": str(sensor_state),\n            "video_on": bool(sensors.get("video", True)),\n            "contact_on": bool(sensors.get("contact", True)),\n            "imu_on": bool(sensors.get("imu", True)),\n        },\n        "m11": {\n            "valence": float(trace_m11.get("valence", _scalar(emotion.get("emotional_valence", affect.get("valence")), 0.0))),\n            "arousal": float(trace_m11.get("arousal", _scalar(emotion.get("emotional_arousal", affect.get("arousal")), 0.0))),\n            "stress": float(trace_m11.get("stress", _scalar(affect.get("stress_latent"), 0.0))),\n            "panic": float(trace_m11.get("panic", _scalar(affect.get("panic_latent"), 0.0))),\n            "curiosity": float(trace_m11.get("curiosity", _scalar(affect.get("curiosity_latent"), 0.0))),\n            "comfort": float(trace_m11.get("comfort", _scalar(affect.get("comfort_latent"), 0.0))),\n            "relief": float(trace_m11.get("relief", _scalar(affect.get("relief_latent"), 0.0))),\n        },\n        "m13": {\n            "relevance": float(trace_m13.get("relevance", _scalar(m13.get("retrieval_relevance"), 0.0))),\n            "episodes": float(trace_m13.get("episodes", _scalar(m13.get("episode_count", m13.get("retrieved_episode_count")), 0.0))),\n            "summary": _text(trace_m13.get("summary", m13.get("summary", m13.get("last_summary", "")))),\n        },\n        "m4": {\n            "token": _text(trace_m4.get("token", m4.get("identity_token", ""))),\n            "gate": float(trace_m4.get("gate", _scalar(m4.get("dynamic_memory_gate"), 0.0))),\n            "stability": float(trace_m4.get("stability", _scalar(m4.get("identity_stability"), 0.0))),\n            "novelty": float(trace_m4.get("novelty", _scalar(m4.get("identity_novelty"), 0.0))),\n            "sentence": _text(trace_m4.get("sentence", m4.get("selected_sentence", ""))),\n        },\n        "m2": {\n            "replay_gate": float(trace_m2.get("replay_gate", _scalar(m2.get("replay_gate"), 0.0))),\n            "should_replay": float(trace_m2.get("should_replay", _scalar(m2.get("should_replay"), 0.0))),\n            "dream_pressure": float(trace_m2.get("dream_pressure", _scalar(m2.get("dream_pressure"), 0.0))),\n            "event_salience": float(trace_m2.get("event_salience", _scalar(m2.get("event_salience"), 0.0))),\n            "source": _text(trace_m2.get("source", m2.get("replay_source", ""))),\n            "identity": _text(trace_m2.get("identity", m2.get("selected_identity_token", ""))),\n        },\n        "m5": {\n            "seed_gate": float(trace_m5.get("seed_gate", _scalar(seed_gate, 0.0))),\n            "seed_norm": float(trace_m5.get("seed_norm", _norm(seed, 0.0))),\n            "feedback_gate": float(trace_m5.get("feedback_gate", _scalar(focus_feedback.get("total_gate", attention.get("focus_feedback_gate")), 0.0))),\n            "feedback_active": float(trace_m5.get("feedback_active", _scalar(focus_feedback.get("active"), 0.0))),\n        },\n        "m3": {\n            "sleep_blocked": bool(trace_m3.get("sleep_blocked", sleep_motor.get("blocked", False))),\n            "blocked_norm": float(trace_m3.get("blocked_norm", _scalar(sleep_motor.get("blocked_motor_norm"), 0.0))),\n            "stage": _text(trace_m3.get("stage", sleep_motor.get("stage", ""))),\n            "blocked_keys": list(sleep_motor.get("blocked_keys", []) or []),\n        },\n        "trace_present": bool(trace),\n    }\n\n\n__all__ = ["build_sleep_replay_monitor_status"]\n'
TEST_FILE = 'from __future__ import annotations\n\nfrom types import SimpleNamespace\n\nimport torch\n\n\nclass DummySystem:\n    def __init__(self) -> None:\n        self.global_step = 42\n        self.video_sensor_enabled = False\n        self.contact_sensor_enabled = False\n        self.imu_sensor_enabled = False\n        self.latest_out = {\n            "affect": {\n                "stress_latent": torch.tensor([[0.4]]),\n                "panic_latent": torch.tensor([[0.2]]),\n                "curiosity_latent": torch.tensor([[0.7]]),\n            },\n            "autobiographical_memory": {\n                "retrieval_relevance": torch.tensor([[0.5]]),\n                "retrieved_episode_count": torch.tensor([[3.0]]),\n                "summary": "episode",\n            },\n            "long_dynamic_memory": {\n                "identity_token": "obj:test",\n                "dynamic_memory_gate": torch.tensor([[0.8]]),\n                "identity_stability": torch.tensor([[0.9]]),\n                "identity_novelty": torch.tensor([[0.1]]),\n            },\n            "event_dream_replay": {\n                "replay_context": torch.ones(1, 256),\n                "replay_gate": torch.tensor([[1.0]]),\n                "dream_pressure": torch.tensor([[0.75]]),\n                "event_salience": torch.tensor([[0.55]]),\n                "should_replay": torch.tensor([[1.0]]),\n                "replay_source": "test",\n            },\n            "sleep_motor_guard": {\n                "blocked": True,\n                "blocked_motor_norm": 1.25,\n                "blocked_keys": ["embodied_targets", "hand_ctrl"],\n                "stage": "main",\n            },\n        }\n\n    def is_full_sleep_mode(self):\n        return True\n\n    def sensor_state_label(self):\n        return "sleep"\n\n    def input_sensors_enabled_dict(self):\n        return {"video": False, "contact": False, "imu": False}\n\n\ndef test_build_sleep_replay_monitor_status_compact_payload():\n    from src.modules.m08_debug_visual_control.sleep_replay_monitor_status import build_sleep_replay_monitor_status\n\n    payload = build_sleep_replay_monitor_status(DummySystem())\n    assert payload["global_step"] == 42\n    assert payload["full_sleep"] is True\n    assert payload["sensor_state"] == "sleep"\n    assert payload["m1"]["video_on"] is False\n    assert payload["m11"]["curiosity"] == 0.7\n    assert payload["m13"]["summary"] == "episode"\n    assert payload["m4"]["token"] == "obj:test"\n    assert payload["m2"]["replay_gate"] == 1.0\n    assert payload["m5"]["seed_norm"] > 0\n    assert payload["m3"]["sleep_blocked"] is True\n'
DOC_FILE = '# Sleep Replay Monitor\n\nAdds a dedicated M8 window for watching the live unconscious sleep/replay loop.\n\n## Status payload\n\nRunner status IPC exposes:\n\n```text\nsleep_replay_monitor\n```\n\nwith sections:\n\n```text\nm1  sensor gates\nm11 affect\nm13 autobiographical retrieval\nm4  dynamic identity\nm2  event/dream replay\nm5  FocusFeedbackBoundary seed\nm3  sleep motor guard\n```\n\n## M8 UI\n\nM8 tab receives:\n\n```text\nSleep Replay Monitor\n```\n\nThe window updates from `last_status["sleep_replay_monitor"]` every status poll.\n'

def replace_once(text: str, old: str, new: str, label: str) -> str:
    if new in text:
        print(f'[skip] {label}: already present')
        return text
    if old not in text:
        print(f'[warn] {label}: anchor not found')
        return text
    print(f'[ok] {label}')
    return text.replace(old, new, 1)

def write_files() -> None:
    files = {
        'src/modules/m08_debug_visual_control/sleep_replay_monitor_status.py': MONITOR_STATUS,
        'tests/module_contracts/test_sleep_replay_monitor_status_contract.py': TEST_FILE,
        'docs/architecture/sleep_replay_monitor.md': DOC_FILE,
    }
    for rel, content in files.items():
        target = ROOT / rel
        target.parent.mkdir(parents=True, exist_ok=True)
        if target.exists() and target.read_text(encoding='utf-8') == content:
            print(f'[skip] {rel}: unchanged')
            continue
        target.write_text(content, encoding='utf-8')
        print(f'[ok] wrote {rel}')

def patch_module_status_runtime() -> None:
    path = ROOT / 'src/modules/m08_debug_visual_control/module_status_runtime.py'
    if not path.exists():
        print('[warn] module_status_runtime.py missing')
        return
    text = path.read_text(encoding='utf-8')
    old_text = text
    if 'build_sleep_replay_monitor_status' not in text:
        text = replace_once(text, 'import torch.optim as optim\n', 'import torch.optim as optim\n\nfrom src.modules.m08_debug_visual_control.sleep_replay_monitor_status import build_sleep_replay_monitor_status\n', 'import sleep replay monitor status')
    if '"sleep_replay_monitor": build_sleep_replay_monitor_status(self),' not in text:
        text = replace_once(text, '                "last_module_lab_result": dict(getattr(self, "last_module_lab_result", {}) or {}),\n', '                "last_module_lab_result": dict(getattr(self, "last_module_lab_result", {}) or {}),\n                "sleep_replay_monitor": build_sleep_replay_monitor_status(self),\n', 'add sleep_replay_monitor payload')
    if text != old_text:
        path.write_text(text, encoding='utf-8')
        print('[ok] wrote module_status_runtime.py')
    else:
        print('[skip] no module_status_runtime changes')

